#stock-table tbody tr {
  border-bottom: 1px solid #eee;
  transition: background 0.15s;
}

#stock-table tbody tr:hover {
  background: #f0f4ff;
}

#stock-table tbody tr.highlighted {
  background: #ffe082;
  font-weight: 600;
}

#stock-table tbody td {
  padding: 7px 10px;
  vertical-align: middle;
}

/* Tooltip */
#tooltip {
  position: fixed;
  display: none;
  background: rgba(30, 30, 40, 0.92);
  color: #fff;
  padding: 8px 12px;
  border-radius: 6px;
  font-size: 0.82rem;
  line-height: 1.5;
  pointer-events: none;
  z-index: 9999;
  max-width: 220px;
  box-shadow: 0 3px 12px rgba(0,0,0,0.25);
}

/* Legend */
.legend text {
  font-family: inherit;
}

/* Bubble selected ring */
g.bubble.selected circle {
  stroke: #222 "'!important;
  stroke-width: 3px !important;
